def alphabet_war(fight):
    n = len(fight)
    survivors = []
    for i in range(n):
        if fight[i] == '*':
            continue
        killed = False
        if i > 0 and fight[i - 1] == '*':
            killed = True
        if i + 1 < n and fight[i + 1] == '*':
            killed = True
        if not killed:
            survivors.append(fight[i])

    left = 0
    right = 0
    lmap = {'w': 4, 'p': 3, 'b': 2, 's': 1}
    rmap = {'m': 4, 'q': 3, 'd': 2, 'z': 1}
    for c in survivors:
        if c in lmap:
            left += lmap[c]
        elif c in rmap:
            right += rmap[c]

    if left > right:
        return "Left side wins!"
    elif right > left:
        return "Right side wins!"
    else:
        return "Let's fight again!"

