import sys

def getAllPrimeFactors(n: int) -> list[int]:
    if n <= 0:
        return []
    factors = []
    while n % 2 == 0:
        factors.append(2)
        n //= 2
    i = 3
    while i * i <= n:
        while n % i == 0:
            factors.append(i)
            n //= i
        i += 2
    if n > 1:
        factors.append(n)
    if not factors:
        return [1]
    return factors

def getUniquePrimeFactorsWithCount(n: int) -> list[list[int]]:
    if n <= 0:
        return [[], []]
    factors = getAllPrimeFactors(n)
    c = Counter(factors)
    primes = sorted(c)
    counts = [c[p] for p in primes]
    return [primes, counts]

def getUniquePrimeFactorsWithProducts(n: int) -> list[int]:
    if n <= 0:
        return []
    factors = getAllPrimeFactors(n)
    c = Counter(factors)
    res = [p ** c[p] for p in sorted(c)]
    if not res:
        return [1]
    return res

