def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def is_mersenne_prime(n):
    if n == 2:
        return True
    if n < 2 or not is_prime(n):
        return False
    M = (1 << n) - 1
    s = 4
    for _ in range(n - 2):
        s = (s * s % M - 2) % M
    return s == 0

