        return None
    left = s[:eq]
    right = s[eq+1:]
    # parse left for strA and op
    i = 0
    nleft = len(left)
    if i < nleft and left[i] == '-':
        i += 1
    while i < nleft and left[i] in '0123456789?':
        i += 1
    if i == nleft or left[i] not in '+-*':
