def parse_num(numstr, d):
    if not numstr:
        return None
    rep = numstr.replace('?', str(d))
    if len(rep) == 0 or (len(rep) == 1 and rep == '-'):
        return None
    sign = 1
    digits = rep
    if rep[0] == '-':
        sign = -1
        digits = rep[1:]
    if len(digits) == 0 or not all(c.isdigit() for c in digits):
        return None
    if len(digits) > 1 and digits[0] == '0':
        return None
    try:
        val = int(digits)
        val *= sign
        if abs(val) > 1000000:
            return None
        return val
    except ValueError:
        return None

