import sys

def isqrt(n):
    if n == 0 or n == 1:
        return n
    l = 1
    r = n // 2 + 1
    while l <= r:
        m = (l + r) // 2
        if m * m <= n:
            l = m + 1
        else:
            r = m - 1
    return r

def is_square(n):
    if n < 0:
        return False
    r = isqrt(n)
    return r * r == n

