for i in range(2, int(MAXA**0.5) + 1):
    if spf[i] == i:
        for j in range(i * i, MAXA, i):
            if spf[j] == j:
                spf[j] = i

prime_to_exps = defaultdict(list)
for num in a:
    if num == 1:
        continue
    cur = num
    while cur > 1:
        p = spf[cur]
        exp = 0
        while cur % p == 0:
            cur //= p
            exp += 1
        prime_to_exps[p].append(exp)

ans = 1
INF = 10**9 + 5
for p, exps in prime_to_exps.items():
    freq = len(exps)
    cnt0 = n - freq
    if cnt0 >= 2:
        continue
    elif cnt0 == 1:
        e = min(exps)
    else:
        min1 = INF
        min2 = INF
        for e_val in exps:
            if e_val < min1:
                min2 = min1
                min1 = e_val
            elif e_val < min2:
                min2 = e_val
        e = min2
    # multiply ans by p**e
    for _ in range(e):
        ans *= p

print(ans)
